                for (uint32_t g = 0; g < numGroups_; g++) {
                    float mu = meanVar[g];
                    float sigma = sqrtf(meanVar[numGroups_ + g] + 1e-5f);
                    uint32_t gStart = g * groupSize;
                    AscendC::Sub<float, float>(yLocal[gStart], yLocal[gStart], mu, groupSize);
